import React from "react"
import "../styles/AboutMe.scss"

export const AboutMe = () => {
    const meImg = '/me3.png'; // use built public asset
    const seo = 'https://i.imgur.com/3BWS4jE.png';
    return (
        <div className="row about_me">
            <img className="col-lg-3 about_me_img" src={meImg} alt="me" aria-label="A picture of me"
                style={{ maxHeight: "25rem", maxWidth: "25rem" }} id="me" />
            <div className="col-lg-7 about_me_text">
                <span style={{ fontSize: "3rem" }}>Hello my name is Radu</span>
                <br />
                <span style={{ fontSize: "2rem" }}>I am a software developer.</span>
                <br />
                <br />
                I study ICT engineering at VIA University and I am
                specialised in cross media.
                <br />
                I like everything about web development be it front-end or back-end.
                <br />
                I enjoy building fast and reliable web services, web apps and web sites.
                <br />
                Recently I started studying about SEO and web performance and optimisation, so I
                decided to re-write my website with this in mind.
                <br />
                The results are satisfying
                <br />
                <img src={seo} alt="audit results" aria-label="audit results"
                    style={{ maxWidth: "320px", padding: "10px" }} />
                <br />
                I also like to code in Python, Java and C# and I have experience working with
                big Java/Javascript code bases thanks to my internship.
                <br />
                <br />
                I love nature and care about a cleaner future.
                <br />
                <br />
            </div>
        </div>
    )
}
